<?php

namespace App\Http\Controllers\Vendor;

use App\Http\Controllers\Controller;
use Illuminate\Http\Request;
use App\Models\Ticket;
use App\Models\AppVendor;
use App\Models\TicketVendorPass;
use App\Models\VendorInvoice;
use Illuminate\Support\Facades\Auth;

class ServiceRequestController extends Controller
{
    public function index()
    {
        $vendor = AppVendor::find(session('vid'));
        
        // Find tickets that are available for this vendor
        $availableRequests = Ticket::where('vendor_service_status', 'broadcasting')
            ->whereNotIn('id', function($query) use ($vendor) {
                $query->select('ticket_id')
                      ->from('ticket_vendor_passes')
                      ->where('vendor_id', $vendor->id);
            })
            // In a real system, you'd match the ticket's vendor_category to the vendor's service_categories
            // For now, we rely on phase logic:
            ->where(function($q) use ($vendor) {
                // Phase 1: Featured
                $q->where(function($q1) use ($vendor) {
                    $q1->where('vendor_broadcast_phase', 1);
                    if (!$vendor->is_featured) {
                        $q1->whereRaw('1 = 0'); // Deny if not featured
                    }
                });
                
                // Phase 2: High Rating
                $q->orWhere(function($q2) use ($vendor) {
                    $q2->where('vendor_broadcast_phase', 2);
                    if ($vendor->global_rating < 4.0) {
                        $q2->whereRaw('1 = 0'); // Deny if rating is low
                    }
                });
                
                // Phase 3: All
                $q->orWhere('vendor_broadcast_phase', 3);
            })
            ->get();

        // Find tickets already accepted by this vendor
        $activeRequests = Ticket::where('assigned_vendor_id', $vendor->id)
            ->whereIn('vendor_service_status', ['accepted', 'negotiating'])
            ->get();
            
        $completedRequests = Ticket::where('assigned_vendor_id', $vendor->id)
            ->where('vendor_service_status', 'completed')
            ->get();

        return view('vendor.services.index', compact('availableRequests', 'activeRequests', 'completedRequests'));
    }

    public function accept(Request $request, $id)
    {
        $vendor = AppVendor::find(session('vid'));
        $ticket = Ticket::findOrFail($id);

        if ($ticket->vendor_service_status !== 'broadcasting') {
            return redirect()->back()->with('error', 'This request is no longer available.');
        }

        $ticket->update([
            'vendor_service_status' => 'negotiating',
            'assigned_vendor_id' => $vendor->id,
            'vendor_accepted_at' => now(),
        ]);

        return redirect()->back()->with('success', 'Request accepted! Please negotiate the details with the resident.');
    }

    public function pass(Request $request, $id)
    {
        $vendor = AppVendor::find(session('vid'));
        
        $request->validate([
            'comment' => 'required|string|max:500'
        ]);

        TicketVendorPass::create([
            'ticket_id' => $id,
            'vendor_id' => $vendor->id,
            'comment' => $request->comment,
        ]);

        return redirect()->back()->with('success', 'You have passed on this request.');
    }

    public function generateInvoice(Request $request, $id)
    {
        $vendor = AppVendor::find(session('vid'));
        $ticket = Ticket::where('assigned_vendor_id', $vendor->id)->findOrFail($id);

        $request->validate([
            'amount' => 'required|numeric|min:0',
            'task_details' => 'required|string'
        ]);

        // Generate Invoice record
        VendorInvoice::create([
            'vendor_id' => $vendor->id,
            'ticket_id' => $ticket->id,
            'amount' => $request->amount,
            'task_details' => $request->task_details,
            'member_id' => $ticket->member_id,
            'resident_id' => $ticket->resident_id,
            'organization_id' => $ticket->organization_id,
            'status' => 'Pending',
            'invoice_file' => 'Generated by system', // Could be a PDF path
        ]);

        $ticket->update([
            'vendor_invoice_amount' => $request->amount,
            // remain in negotiating or go to accepted? We'll leave it in negotiating until complete.
        ]);

        return redirect()->back()->with('success', 'Invoice generated successfully.');
    }

    public function complete($id)
    {
        $vendor = AppVendor::find(session('vid'));
        $ticket = Ticket::where('assigned_vendor_id', $vendor->id)->findOrFail($id);

        $ticket->update([
            'vendor_service_status' => 'completed',
            'status' => 'resolved'
        ]);

        return redirect()->back()->with('success', 'Service marked as completed!');
    }
}
